import { Component, OnInit, inject } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { AuthRequest } from '../../models/auth.model';

@Component({
  selector: 'app-login',
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss']
})
export class LoginComponent implements OnInit {
  loginForm!: FormGroup;
  loading = false;
  submitted = false;
  error: string | null = null;
  showPassword = false;

  private formBuilder = inject(FormBuilder);
  private authService = inject(AuthService);
  private router = inject(Router);

  ngOnInit(): void {
    // Redirect to dashboard if already logged in
    if (this.authService.isAuthenticated()) {
      this.router.navigate(['/tasks']);
    }

    this.initializeForm();
  }

  initializeForm(): void {
    this.loginForm = this.formBuilder.group({
      username: ['', [Validators.required, Validators.minLength(3)]],
      password: ['', [Validators.required, Validators.minLength(8)]]
    });
  }

  get f() {
    return this.loginForm.controls;
  }

  onSubmit(): void {
    this.submitted = true;
    this.error = null;

    // Stop if form is invalid
    if (this.loginForm.invalid) {
      return;
    }

    this.loading = true;
    const authRequest: AuthRequest = {
      username: this.f['username'].value,
      password: this.f['password'].value
    };

    this.authService.login(authRequest).subscribe({
      next: (response) => {
        console.log('Login successful:', response);
        this.loading = false;
        this.router.navigate(['/tasks']);
      },
      error: (error) => {
        console.error('Login failed:', error);
        this.error = error.message || 'Login failed. Please check your credentials.';
        this.loading = false;
      }
    });
  }

  togglePasswordVisibility(): void {
    this.showPassword = !this.showPassword;
  }

  goToSignup(): void {
    this.router.navigate(['/auth/signup']);
  }
}
<div class="login-container">
  <div class="login-card">
    <div class="login-header">
      <h1>Task Flow</h1>
      <p>Plan your day with calm focus</p>
    </div>

    <form [formGroup]="loginForm" (ngSubmit)="onSubmit()" class="login-form">
      <!-- Error Message -->
      @if (error) {
        <div class="alert alert-error">
          <span class="alert-icon">⚠️</span>
          <span>{{ error }}</span>
        </div>
      }

      <!-- Username Field -->
      <div class="form-group">
        <label for="username" class="form-label">Username</label>
        <input
          type="text"
          id="username"
          formControlName="username"
          class="form-control"
          [class.is-invalid]="submitted && f['username'].errors"
          placeholder="Enter your username"
          [disabled]="loading"
        />
        @if (submitted && f['username'].errors) {
          <div class="field-error">
            @if (f['username'].errors['required']) {
              <span>Username is required</span>
            }
            @if (f['username'].errors['minlength']) {
              <span>Username must be at least 3 characters</span>
            }
          </div>
        }
      </div>

      <!-- Password Field -->
      <div class="form-group">
        <label for="password" class="form-label">Password</label>
        <div class="password-input-group">
          <input
            [type]="showPassword ? 'text' : 'password'"
            id="password"
            formControlName="password"
            class="form-control"
            [class.is-invalid]="submitted && f['password'].errors"
            placeholder="Enter your password"
            [disabled]="loading"
          />
          <button
            type="button"
            class="password-toggle"
            (click)="togglePasswordVisibility()"
            [disabled]="loading"
          >
            {{ showPassword ? '🙈' : '👁️' }}
          </button>
        </div>
        @if (submitted && f['password'].errors) {
          <div class="field-error">
            @if (f['password'].errors['required']) {
              <span>Password is required</span>
            }
            @if (f['password'].errors['minlength']) {
              <span>Password must be at least 8 characters</span>
            }
          </div>
        }
      </div>

      <!-- Submit Button -->
      <button
        type="submit"
        class="btn btn-primary btn-block"
        [disabled]="loading || loginForm.invalid"
      >
        @if (!loading) {
          <span>Sign In</span>
        } @else {
          <span class="spinner">
            <span class="spinner-dot"></span> Signing in...
          </span>
        }
      </button>
    </form>

    <!-- Signup Link -->
    <div class="login-footer">
      <p>Don't have an account?
        <a href="javascript:void(0)" (click)="goToSignup()" class="link">Sign up here</a>
      </p>
    </div>
  </div>
</div>
